import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { withStyles } from '@material-ui/core/styles';
import Grid from '@material-ui/core/Grid';
import Typography from '@material-ui/core/Typography';
import Box from '@material-ui/core/Box';
import FooterImg from '../../images/footerImg.png';

const styles = {
  root: {
    flexGrow: 1,
    backgroundColor: 'black',
    backgroundImage: `url(${FooterImg})`,
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    display: 'none', // Först dölj footern
    position: 'fixed',
    bottom: 0,
    left: 0,
    width: '100%',
  },
  show: {
    display: 'block', // Visa footern när användaren har scrollat till slutet
  },
  h: {
    color: 'white',
    flex: 'center',
  },
  row: {},
  colSm: {
    color: 'white',
  },
  link: {
    color: '#FFF',
    textDecoration: 'none',
  },
};

function Footer({ classes }) {
  const { t } = useTranslation();
  const [showFooter, setShowFooter] = useState(false);

  useEffect(() => {
    function handleScroll() {
      const isScrollEnd = window.innerHeight + document.documentElement.scrollTop === document.documentElement.offsetHeight;
      setShowFooter(isScrollEnd);
    }

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <footer className={`${classes.root} ${showFooter ? classes.show : ''}`}>
      <Grid item container direction="column" justifyContent="center" alignItems="center" xs={12}>
        <Grid item xs={10} component={'div'}>
          <Box p={2}>
            <Typography variant="h6" className={classes.h} component="h6">
              {t('welcome_message')}
            </Typography>
          </Box>
          <hr />
        </Grid>
        <div className={classes.row}>
          <Typography variant="body2" component="h2" className={classes.colSm}>
            &copy;{new Date().getFullYear()} <Link to="https://www.limestoneweb.se" className={classes.link}>
            LIMESTONEWEB.SE
            </Link> | All rights reserved | Terms Of Service | Privacy |{' '}
          </Typography>
        </div>
      </Grid>
    </footer>
  );
}

export default withStyles(styles)(Footer);
